export interface InterviewQuestion {
  id: string;
  question: string;
  answer: string;
  code?: string;
  codeLanguage?: string;
  explanation: string;
}

export interface InterviewTopic {
  id: string;
  title: string;
  icon: string;
  questions: InterviewQuestion[];
}

export const coreJavaInterviewTopics: InterviewTopic[] = [
  {
    id: "basics",
    title: "Java Basics",
    icon: "☕",
    questions: [
      { id:"b1", question:"What is Java? What are its main features?", answer:"Java is a high-level, object-oriented, platform-independent language following WORA.", code:`public class HelloWorld {\n    public static void main(String[] args) {\n        System.out.println("Hello, Java!");\n    }\n}`, codeLanguage:"java", explanation:"Key features: Platform Independent (bytecode on JVM), Object-Oriented, Simple (no pointers), Secure (bytecode verification), Robust (exception handling, GC), Multithreaded, Architecture Neutral (fixed primitive sizes), High Performance (JIT)." },
      { id:"b2", question:"Difference between JDK, JRE, and JVM?", answer:"JDK=full dev kit, JRE=runtime env, JVM=virtual machine executing bytecode.", code:`JDK = JRE + Dev Tools (javac, jar, javadoc)\nJRE = JVM + Core Libraries\nJVM = Bytecode Executor`, codeLanguage:"plaintext", explanation:"JVM converts bytecode→machine code. JRE=JVM+libraries (minimum to RUN). JDK=JRE+dev tools (required to DEVELOP). Relationship: JDK ⊃ JRE ⊃ JVM." },
      { id:"b3", question:"What is bytecode in Java?", answer:"Intermediate code from javac, not machine code—instructions for JVM making Java platform-independent.", code:`.java → javac → .class (bytecode) → JVM → machine code`, codeLanguage:"plaintext", explanation:"Same .class runs on any OS with JVM. Bytecode is verified before execution (security). JIT compiler optimizes at runtime (performance)." },
      { id:"b4", question:"Difference between path and classpath?", answer:"PATH: OS finds executables (javac, java). CLASSPATH: JVM finds user classes and packages.", code:`PATH=C:\\jdk-17\\bin (OS level)\nCLASSPATH=.;C:\\lib\\* (JVM level)`, codeLanguage:"shell", explanation:"PATH is for the OS to find JDK tools. CLASSPATH is for the JVM to find your .class files and JARs. '.' means current directory." },
      { id:"b5", question:"Why is Java not 100% object-oriented?", answer:"Java has primitive types (int, char, boolean) which are not objects, and static members usable without objects.", code:`int x = 10;        // NOT an object\nInteger xObj = 10;  // IS an object (wrapper)\nstatic int count;   // no object needed`, codeLanguage:"java", explanation:"Primitives (int, char, byte, etc.) are NOT objects. Static members belong to class, not instances. No multiple class inheritance. Wrapper classes bridge the gap but primitives remain for performance." },
      { id:"b6", question:"What are the primitive data types in Java?", answer:"8 primitives: byte(1B), short(2B), int(4B), long(8B), float(4B), double(8B), char(2B), boolean(1bit).", code:`byte b=127; short s=32767; int i=2147483647;\nlong l=999999L; float f=3.14f; double d=3.14;\nchar c='A'; boolean bool=true;`, codeLanguage:"java", explanation:"Sizes are fixed across platforms (architecture neutral). Default values apply to fields only; locals must be initialized. Each primitive has a corresponding wrapper class." },
      { id:"b7", question:"What is type casting? Widening vs narrowing?", answer:"Type casting converts one type to another. Widening: smaller→larger (automatic). Narrowing: larger→smaller (explicit, may lose data).", code:`// Widening (auto)\nint i=100; long l=i; double d=l;\n// Narrowing (explicit)\ndouble d=166.78; int i=(int)d; // 166`, codeLanguage:"java", explanation:"Widening: byte→short→int→long→float→double. No data loss. Narrowing: reverse direction, explicit cast required, fractional part truncated." },
      { id:"b8", question:"What is autoboxing and unboxing?", answer:"Autoboxing: primitive→wrapper (auto). Unboxing: wrapper→primitive (auto).", code:`Integer obj = 42;    // autoboxing: int→Integer\nint prim = obj;      // unboxing: Integer→int\nList<Integer> list = new ArrayList<>();\nlist.add(10);        // autoboxing\nint v = list.get(0); // unboxing`, codeLanguage:"java", explanation:"Autoboxing happens when adding primitives to Collections. Unboxing happens during arithmetic/assignment. Caution: unboxing null→NPE. Integer caches -128 to 127." },
      { id:"b9", question:"Difference between == and .equals()?", answer:"== compares references for objects (values for primitives). .equals() compares content when overridden.", code:`String s1=new String("Hi"), s2=new String("Hi");\ns1==s2;      // false (different objects)\ns1.equals(s2); // true (same content)\nString s3="Hi", s4="Hi";\ns3==s4;      // true (same pool ref)`, codeLanguage:"java", explanation:"Use == for primitives and null checks. Use .equals() for object content comparison. String and wrappers override .equals(). Integer caches -128 to 127 so == may work by coincidence." },
      { id:"b10", question:"What is the main() method? Why public static void?", answer:"Entry point for JVM. public=JVM access, static=no object needed, void=no return to JVM.", code:`public static void main(String[] args) {\n    System.out.println("Entry point");\n}`, codeLanguage:"java", explanation:"public: JVM accesses from outside. static: JVM calls before objects exist. void: no return value. main: fixed name. String[] args: command-line arguments. Valid: main(String... args) too." },
    ],
  },
  {
    id: "oops",
    title: "OOP Concepts",
    icon: "🧱",
    questions: [
      { id:"o1", question:"What are the four pillars of OOP?", answer:"Encapsulation, Inheritance, Polymorphism, Abstraction.", code:`// Encapsulation: private fields + public methods\nclass BankAccount {\n    private double balance;\n    public void deposit(double a) { if(a>0) balance+=a; }\n}\n// Inheritance: child extends parent\nclass Dog extends Animal { }\n// Polymorphism: same interface, different behavior\nclass Circle extends Shape { double area() { return Math.PI*r*r; } }\n// Abstraction: hide complexity\nabstract class Vehicle { abstract void start(); }`, codeLanguage:"java", explanation:"Encapsulation: bundle data+methods, restrict access. Inheritance: child acquires parent properties. Polymorphism: many forms (overloading+overriding). Abstraction: show what, hide how." },
      { id:"o2", question:"Method overloading vs overriding?", answer:"Overloading: same name, different params, same class, compile-time. Overriding: same signature, parent-child, runtime.", code:`// Overloading\nint add(int a, int b) { return a+b; }\ndouble add(double a, double b) { return a+b; }\n// Overriding\nclass Dog extends Animal {\n    @Override void sound() { System.out.println("Bark"); }\n}`, codeLanguage:"java", explanation:"Overloading=compile-time, same class, params must differ. Overriding=runtime, parent-child, same signature. Cannot override static/final methods. @Override annotation recommended." },
      { id:"o3", question:"What is encapsulation? How achieved?", answer:"Bundling data+methods while restricting direct access. Achieved via private fields + public getters/setters.", code:`class Employee {\n    private int age;\n    public void setAge(int age) {\n        if(age>0 && age<150) this.age=age;\n    }\n    public int getAge() { return age; }\n}`, codeLanguage:"java", explanation:"Private fields prevent direct access. Public setters with validation control writes. Getters control reads. Can make read-only (no setter) or write-only (no getter)." },
      { id:"o4", question:"What is inheritance? Types in Java?", answer:"Child class acquires parent properties. Types: single, multilevel, hierarchical (classes); multiple (interfaces only).", code:`class Dog extends Animal { }  // single\nclass ElectricCar extends Car { } // multilevel\ninterface Flyable { void fly(); }\ninterface Swimmable { void swim(); }\nclass Duck implements Flyable, Swimmable { } // multiple`, codeLanguage:"java", explanation:"No multiple class inheritance (Diamond Problem). extends=class, implements=interface. Single, multilevel, hierarchical, multiple (interfaces), hybrid." },
      { id:"o5", question:"Abstract class vs Interface?", answer:"Abstract class: partial abstraction, has constructors, instance vars, concrete methods. Interface: full abstraction, no instance vars, no constructors, default methods from Java 8.", code:`abstract class Animal {\n    abstract void sound();\n    void breathe() { } // concrete\n    String name; // instance var\n}\ninterface Drawable {\n    void draw(); // abstract\n    default void resize() { } // Java 8\n}`, codeLanguage:"java", explanation:"Abstract class: single inheritance, any access modifier, has state. Interface: multiple implementation, public abstract by default, no state (only constants). Use abstract class for shared state; interface for capability contract." },
      { id:"o6", question:"What is polymorphism?", answer:"'Many forms'. Compile-time (overloading) and Runtime (overriding + upcasting).", code:`// Compile-time: overloading\nvoid show(int a) { }\nvoid show(String a) { }\n// Runtime: overriding + parent reference\nShape s = new Circle();\ns.area(); // Circle's version at runtime`, codeLanguage:"java", explanation:"Compile-time=static binding, method overloading, faster. Runtime=dynamic binding, method overriding, parent ref=child object, JVM decides at runtime. More flexible." },
      { id:"o7", question:"What is the 'this' keyword?", answer:"Reference to current object. Used to: distinguish fields from params, chain constructors, pass/return current object.", code:`Student(String name) { this.name=name; } // distinguish\nStudent() { this("Unknown"); } // constructor chaining\nStudent setName(String n) { this.name=n; return this; } // chaining`, codeLanguage:"java", explanation:"this() must be first statement in constructor. Cannot use in static context. return this enables fluent API/method chaining." },
      { id:"o8", question:"What is the 'super' keyword?", answer:"Reference to immediate parent class. Call parent constructors, access parent methods/variables.", code:`Dog() { super("Default"); } // parent constructor\nSystem.out.println(super.name); // parent variable\nsuper.sound(); // parent method in overriding`, codeLanguage:"java", explanation:"super() must be first statement. If parent has no default constructor, child MUST call super(args). Refers to immediate parent only. Cannot use in static context." },
      { id:"o9", question:"What are access modifiers?", answer:"private(class), default(package), protected(package+subclasses), public(everywhere).", code:`private int a;    // class only\nint b;            // package (default)\nprotected int c;  // package + subclasses\npublic int d;     // everywhere`, codeLanguage:"java", explanation:"Most→least restrictive: private→default→protected→public. Best practice: fields private, public getters/setters, protected for subclass methods. Top-level classes: public or default only." },
      { id:"o10", question:"What is the 'static' keyword?", answer:"Belongs to class, not instances. Shared across all objects. Can access without creating object.", code:`class Counter {\n    static int count=0; // shared\n    int id; // unique per instance\n    Counter() { count++; id=count; }\n    static int getCount() { return count; }\n}`, codeLanguage:"java", explanation:"Static: variable (shared), method (no this, no instance access), block (runs once on class load), nested class (no outer instance). Use for utility methods, constants, counters, factory methods." },
    ],
  },
  {
    id: "strings",
    title: "String Handling",
    icon: "📝",
    questions: [
      { id:"s1", question:"What is the String Pool?", answer:"Special heap area where String literals are stored and reused. Saves memory.", code:`String s1="Hello"; String s2="Hello";\ns1==s2; // true (same pool ref)\nString s3=new String("Hello");\ns1==s3; // false (heap, not pool)\ns1==s3.intern(); // true (added to pool)`, codeLanguage:"java", explanation:"Literals auto-pooled. new String() creates heap object. intern() adds to pool. Compile-time concat→pool; runtime concat→heap. Immutability makes pool safe." },
      { id:"s2", question:"Why is String immutable?", answer:"For String Pool safety, security, thread-safety, hashcode caching, and class loading reliability.", code:`String s1="Hello";\nString s2=s1.concat(" World"); // NEW object\nSystem.out.println(s1); // "Hello" unchanged`, codeLanguage:"java", explanation:"Pool safety: shared refs can't corrupt each other. Security: class names, URLs can't be tampered. Thread-safe: no sync needed. Hashcode cached: HashMap fast. Enforced by: final class, private final char[]/byte[], no mutating methods." },
      { id:"s3", question:"String vs StringBuilder vs StringBuffer?", answer:"String: immutable. StringBuilder: mutable, not thread-safe, fast. StringBuffer: mutable, thread-safe (synchronized), slower.", code:`StringBuilder sb=new StringBuilder("Hi");\nsb.append(" World"); // modifies same object\nStringBuffer sbuf=new StringBuffer("Hi");\nsbuf.append(" World"); // synchronized methods`, codeLanguage:"java", explanation:"String=slowest for concatenation (new objects). StringBuilder=fastest, single-thread. StringBuffer=medium, multi-thread. Use String for constants, StringBuilder for building, StringBuffer for multi-thread (rare)." },
      { id:"s4", question:"Important String methods?", answer:"charAt, substring, equals, compareTo, contains, split, trim, replace, length, indexOf, toUpperCase, join, isEmpty.", code:`String s="Hello, World!";\ns.length(); s.charAt(0); s.substring(7);\ns.equals("hi"); s.equalsIgnoreCase("hello, world!");\ns.contains("World"); s.indexOf("World");\ns.replace('o','0'); s.trim();\nString.join("-","a","b"); "a,b".split(",");`, codeLanguage:"java", explanation:"Categories: Access(length,charAt), Extraction(substring), Comparison(equals,compareTo), Search(indexOf,contains), Modification(replace,trim,toUpperCase), Split/Join, Check(isEmpty,isBlank). Pitfall: substring end is exclusive." },
      { id:"s5", question:"equals() vs contentEquals()?", answer:"equals() only compares with String objects. contentEquals() compares with any CharSequence (StringBuffer, StringBuilder).", code:`String s="Hello";\nStringBuffer sb=new StringBuffer("Hello");\ns.equals(sb); // false (not a String)\ns.contentEquals(sb); // true (char sequence)`, codeLanguage:"java", explanation:"equals() checks instanceof String first. contentEquals() accepts any CharSequence, compares char-by-char. Use contentEquals when comparing with StringBuilder/StringBuffer." },
    ],
  },
  {
    id: "inheritance-polymorphism",
    title: "Inheritance & Polymorphism Deep Dive",
    icon: "🔗",
    questions: [
      { id:"ip1", question:"Can you override a static method?", answer:"No. Redefining static method in subclass is 'method hiding', not overriding. Reference type decides which is called.", code:`class Parent { static void show() { System.out.println("P"); } }\nclass Child extends Parent { static void show() { System.out.println("C"); } }\nParent p=new Child(); p.show(); // "P" — ref type decides`, codeLanguage:"java", explanation:"Static methods use static binding (compile-time). No virtual dispatch. Called on class, not instance. Always call static methods via class name for clarity." },
      { id:"ip2", question:"What is covariant return type?", answer:"Overriding method can return a subtype of parent method's return type. Java 5+.", code:`class AnimalFactory { Animal create() { return new Animal(); } }\nclass DogFactory extends AnimalFactory {\n    @Override Dog create() { return new Dog(); } // covariant\n}`, codeLanguage:"java", explanation:"Return type must be subtype. Only for reference types. Method signature must still match. True overriding, not overloading." },
      { id:"ip3", question:"Diamond Problem? How does Java handle it?", answer:"When class inherits from two with same method. Java prevents by disallowing multiple class inheritance. For interface default methods, class must override to resolve conflict.", code:`interface A { default void show() { System.out.println("A"); } }\ninterface B { default void show() { System.out.println("B"); } }\nclass C implements A, B {\n    public void show() { A.super.show(); } // resolve explicitly\n}`, codeLanguage:"java", explanation:"No multiple class inheritance = no Diamond Problem. For conflicting default methods, class MUST override. Use InterfaceName.super.method() to choose implementation." },
      { id:"ip4", question:"Can constructor be inherited/overridden?", answer:"No. Constructors are not inherited or overridable. Each class has its own. Subclass calls parent via super().", code:`class Parent { Parent(String n) { } }\nclass Child extends Parent {\n    Child() { super("default"); } // must call parent\n}`, codeLanguage:"java", explanation:"Constructors are initialization blocks, not members. Not inherited. If parent has no default constructor, child MUST call super(args). super() must be first statement." },
      { id:"ip5", question:"Composition vs Inheritance?", answer:"Composition: has-a (contains reference). Inheritance: is-a (extends). Prefer composition for flexibility.", code:`// Inheritance (is-a)\nclass Car extends Vehicle { }\n// Composition (has-a)\nclass Car { private Engine engine; }`, codeLanguage:"java", explanation:"Inheritance: tight coupling, static, subclass depends on parent. Composition: loose coupling, dynamic, can change implementation at runtime. Prefer composition: easier to change, better encapsulation, avoids fragile base class." },
    ],
  },
  {
    id: "exception-handling",
    title: "Exception Handling",
    icon: "⚠️",
    questions: [
      { id:"e1", question:"What is exception handling? Checked vs Unchecked?", answer:"Managing runtime errors. Checked: compiler enforces handling (IOException). Unchecked: RuntimeException, not enforced.", code:`// Checked — must catch or declare\ntry { new FileReader("file.txt"); }\ncatch (IOException e) { }\n// Unchecked — not enforced\nint[] a=new int[3]; a[5]=10; // ArrayIndexOutOfBounds`, codeLanguage:"java", explanation:"Checked: must catch or throws. Examples: IOException, SQLException. Unchecked: RuntimeException subclasses, not enforced. Examples: NPE, ArithmeticException. Error: serious JVM issues, don't catch." },
      { id:"e2", question:"throw vs throws?", answer:"throw explicitly throws an exception. throws declares possible exceptions in method signature.", code:`void setAge(int age) {\n    if(age<0) throw new IllegalArgumentException();\n}\nvoid read() throws IOException { new FileReader("f"); }`, codeLanguage:"java", explanation:"throw: inside method, throws one exception. throws: in signature, declares multiple. throw=new exception object. throws=exception class names." },
      { id:"e3", question:"What is the finally block?", answer:"Always executes after try-catch. Used for cleanup. Only skipped by System.exit() or JVM crash.", code:`try { int r=10/0; }\ncatch(ArithmeticException e) { System.out.println("Caught"); }\nfinally { System.out.println("Always runs"); }`, codeLanguage:"java", explanation:"finally always runs: with/without exception, even if catch returns. Only skipped: System.exit(), JVM crash. Caution: finally's return overrides try/catch return. Prefer try-with-resources." },
      { id:"e4", question:"What is try-with-resources?", answer:"Java 7+ feature that auto-closes AutoCloseable resources. No finally needed.", code:`try (FileReader fr=new FileReader("f");\n     BufferedReader br=new BufferedReader(fr)) {\n    br.readLine();\n} catch(IOException e) { }`, codeLanguage:"java", explanation:"Resources in try() auto-closed in reverse order. Must implement AutoCloseable. Suppressed exceptions accessible via getSuppressed(). Prefer over manual finally." },
      { id:"e5", question:"Can you have try without catch?", answer:"Yes. try-finally or try-with-resources without catch. Exception propagates but cleanup runs.", code:`void read() throws IOException {\n    try (FileReader fr=new FileReader("f")) {\n        // exception propagates, fr auto-closed\n    }\n}`, codeLanguage:"java", explanation:"Use when current method can't handle exception but must clean up. try-finally or try-with-resources both valid without catch." },
      { id:"e6", question:"How to create custom exception?", answer:"Extend Exception (checked) or RuntimeException (unchecked). Add constructors and custom fields.", code:`class InsufficientFundsException extends Exception {\n    private double amount;\n    InsufficientFundsException(double amt) {\n        super("Insufficient: "+amt);\n        this.amount=amt;\n    }\n}`, codeLanguage:"java", explanation:"Extend Exception for checked (caller must handle), RuntimeException for unchecked. Add custom fields for context. Call super(message). Naming: XxxException." },
      { id:"e7", question:"Error vs Exception?", answer:"Error: serious JVM problems (OutOfMemoryError), don't catch. Exception: application-level, can be caught and handled.", code:`// Error — don't catch\n// OutOfMemoryError, StackOverflowError\n// Exception — catch and handle\ntry { int x=10/0; }\ncatch(ArithmeticException e) { }`, codeLanguage:"java", explanation:"Both extend Throwable. Error: JVM-level, not recoverable. Exception: application-level, recoverable. Don't catch Errors—fix root cause." },
      { id:"e8", question:"What is exception propagation?", answer:"Uncaught exception moves up the call stack until caught or program terminates.", code:`void m3() { throw new ArithmeticException(); }\nvoid m2() { m3(); }\nvoid m1() { m2(); }\nvoid main() { try { m1(); } catch(ArithmeticException e) { } }`, codeLanguage:"java", explanation:"Unchecked auto-propagate. Checked must be declared with throws at each level. If never caught, JVM prints stack trace and terminates." },
      { id:"e9", question:"What are suppressed exceptions?", answer:"When try block throws and close() also throws. Try exception=primary, close exception=suppressed.", code:`try (MyResource r=new MyResource()) {\n    throw new RuntimeException("Try");\n} catch(RuntimeException e) {\n    for(Throwable s : e.getSuppressed()) System.out.println(s);\n}`, codeLanguage:"java", explanation:"In try-with-resources: try exception primary, close() suppressed. Access via getSuppressed(). Traditional try-finally loses the try exception if finally also throws." },
      { id:"e10", question:"final vs finally vs finalize?", answer:"final: keyword (constant/lock). finally: block after try-catch. finalize: deprecated pre-GC method.", code:`final int MAX=100; // can't reassign\ntry { } finally { } // always runs\nclass Old {\n    @Deprecated protected void finalize() { } // don't use\n}`, codeLanguage:"java", explanation:"final: variable=constant, method=no override, class=no extend. finally: cleanup block. finalize: deprecated since Java 9, unreliable. Use try-with-resources or Cleaners instead." },
    ],
  },
  {
    id: "collections",
    title: "Collections Framework",
    icon: "📦",
    questions: [
      { id:"c1", question:"What is the Collections Framework?", answer:"Unified architecture for collections: interfaces (List, Set, Map), implementations (ArrayList, HashMap), and algorithms (Collections.sort).", code:`List<String> list=new ArrayList<>();\nSet<String> set=new HashSet<>();\nMap<String,Integer> map=new HashMap<>();\nCollections.sort(list);`, codeLanguage:"java", explanation:"Interfaces: Collection, List, Set, Map, Queue. Implementations: ArrayList, LinkedList, HashSet, TreeSet, HashMap, TreeMap. Algorithms: sort, shuffle, reverse, binarySearch." },
      { id:"c2", question:"ArrayList vs LinkedList?", answer:"ArrayList: dynamic array, O(1) access, O(n) insert/delete. LinkedList: doubly-linked list, O(n) access, O(1) insert/delete at ends.", code:`List<String> al=new ArrayList<>(); // fast get\nal.get(0); // O(1)\nLinkedList<String> ll=new LinkedList<>();\nll.addFirst("A"); // O(1)`, codeLanguage:"java", explanation:"ArrayList: better cache locality, less memory overhead. Use for most cases. LinkedList: use for frequent head/tail operations. LinkedList insert/delete at known node is O(1) but finding node is O(n)." },
      { id:"c3", question:"HashMap vs TreeMap vs LinkedHashMap?", answer:"HashMap: unordered O(1). TreeMap: sorted O(log n). LinkedHashMap: insertion/access order O(1).", code:`Map<String,Integer> hm=new HashMap<>(); // no order\nMap<String,Integer> tm=new TreeMap<>(); // sorted keys\nMap<String,Integer> lm=new LinkedHashMap<>(); // insertion order`, codeLanguage:"java", explanation:"HashMap: general purpose. TreeMap: sorted keys (natural/comparator), no null key. LinkedHashMap: preserves order, can be access-order for LRU cache. All: not thread-safe." },
      { id:"c4", question:"HashSet vs TreeSet vs LinkedHashSet?", answer:"HashSet: unordered O(1). TreeSet: sorted O(log n). LinkedHashSet: insertion order O(1).", code:`Set<String> hs=new HashSet<>(); // no order\nSet<String> ts=new TreeSet<>(); // sorted\nSet<String> ls=new LinkedHashSet<>(); // insertion order`, codeLanguage:"java", explanation:"HashSet: fastest, allows null. TreeSet: sorted, no null, elements must be Comparable. LinkedHashSet: preserves insertion order, allows null." },
      { id:"c5", question:"Comparable vs Comparator?", answer:"Comparable: natural ordering in class (compareTo). Comparator: custom ordering outside class (compare). One Comparable, many Comparators.", code:`class Emp implements Comparable<Emp> {\n    int salary;\n    public int compareTo(Emp o) { return salary-o.salary; }\n}\nComparator<Emp> byName=Comparator.comparing(e->e.name);`, codeLanguage:"java", explanation:"Comparable: java.lang, compareTo(T), defined in class, one per class. Comparator: java.util, compare(T,T), separate class, unlimited. Use Comparable for default order, Comparator for alternatives." },
      { id:"c6", question:"How does HashMap work internally?", answer:"Array of buckets. hashCode()→bucket index. Collision→linked list (tree if >8). Resize when size>capacity*0.75.", code:`put(key, value):\n1. hash = key.hashCode()\n2. index = hash & (capacity-1)\n3. If empty → new Node\n4. If occupied → equals() check\n5. If chain>8 → treeify (TreeMap)`, codeLanguage:"plaintext", explanation:"Key: always override hashCode() AND equals() together. Equal objects must have equal hashCodes. Bad hashCode=all entries in one bucket=O(n). Default capacity=16, loadFactor=0.75." },
      { id:"c7", question:"What is ConcurrentHashMap?", answer:"Thread-safe HashMap. Locks only bucket/segment, not entire map. Allows concurrent reads and writes.", code:`ConcurrentMap<String,Integer> map=new ConcurrentHashMap<>();\nmap.putIfAbsent("A",1);\nmap.computeIfAbsent("B", k->2);`, codeLanguage:"java", explanation:"Java 7: segments (16 by default). Java 8+: CAS + synchronized on bucket head. Reads are lock-free. Null keys/values NOT allowed. Use for multi-threaded scenarios." },
      { id:"c8", question:"What is fail-fast vs fail-safe iterator?", answer:"Fail-fast: throws ConcurrentModificationException if collection modified during iteration. Fail-safe: works on copy, no exception.", code:`// Fail-fast: ArrayList, HashMap\nList<String> list=new ArrayList<>();\nfor(String s:list) { list.add("x"); } // CME!\n// Fail-safe: ConcurrentHashMap, CopyOnWriteArrayList\nConcurrentMap<String,Integer> cm=new ConcurrentHashMap<>();\nfor(String k:cm.keySet()) { cm.put("x",1); } // OK`, codeLanguage:"java", explanation:"Fail-fast: checks modCount, throws CME. Most standard collections. Fail-safe: iterates on snapshot/copy. ConcurrentHashMap, CopyOnWriteArrayList. Fail-safe may show stale data." },
      { id:"c9", question:"What is the difference between List and Set?", answer:"List: ordered, allows duplicates, indexed access. Set: unordered (usually), no duplicates, no index.", code:`List<String> list=new ArrayList<>();\nlist.add("A"); list.add("A"); // [A, A]\nSet<String> set=new HashSet<>();\nset.add("A"); set.add("A"); // [A] only`, codeLanguage:"java", explanation:"List: ArrayList, LinkedList, Vector. Allows duplicates, maintains order, positional access. Set: HashSet, TreeSet, LinkedHashSet. No duplicates, HashSet unordered, TreeSet sorted." },
      { id:"c10", question:"What is the difference between Iterator and ListIterator?", answer:"Iterator: forward only, remove only. ListIterator: bidirectional, add/set/remove, has index info. ListIterator works only with List.", code:`// Iterator\nIterator<String> it=list.iterator();\nwhile(it.hasNext()) { it.next(); it.remove(); }\n// ListIterator\nListIterator<String> li=list.listIterator();\nli.add("X"); li.set("Y"); li.previous();`, codeLanguage:"java", explanation:"Iterator: hasNext/next/remove, works with any Collection. ListIterator: hasPrevious/previous/add/set/nextIndex/previousIndex, List only. ListIterator extends Iterator." },
    ],
  },
  {
    id: "multithreading",
    title: "Multithreading",
    icon: "🔀",
    questions: [
      { id:"mt1", question:"What is multithreading? How to create a thread?", answer:"Multithreading: executing multiple threads simultaneously. Create thread by: extending Thread, implementing Runnable, or using Callable+Future.", code:`// Method 1: Extend Thread\nclass MyThread extends Thread {\n    public void run() { System.out.println("Thread: "+getName()); }\n}\nnew MyThread().start();\n\n// Method 2: Implement Runnable\nThread t=new Thread(() -> System.out.println("Runnable"));\nt.start();\n\n// Method 3: Callable + Future\nExecutorService es=Executors.newFixedThreadPool(2);\nFuture<Integer> f=es.submit(() -> 42);\nSystem.out.println(f.get()); // 42`, codeLanguage:"java", explanation:"Thread: override run(), call start(). Runnable: functional interface, better (can extend another class). Callable: returns value, can throw exception. ExecutorService: thread pool management. Always call start(), not run() directly." },
      { id:"mt2", question:"Thread vs Runnable?", answer:"Thread is a class. Runnable is an interface. Prefer Runnable: can extend another class, separation of concerns, usable with executor frameworks.", code:`// Thread — must extend Thread (single inheritance)\nclass MyThread extends Thread {\n    public void run() { /* task */ }\n}\n// Runnable — implement interface (can extend other class)\nclass MyTask implements Runnable {\n    public void run() { /* task */ }\n}\nnew Thread(new MyTask()).start();`, codeLanguage:"java", explanation:"Runnable preferred: Java doesn't support multiple inheritance, implementing Runnable leaves extends available. Each Thread has significant overhead; Runnable decouples task from thread. Runnable works with ExecutorService." },
      { id:"mt3", question:"What is the synchronized keyword?", answer:"synchronized controls access to shared resources by only allowing one thread at a time into a block/method.", code:`// Synchronized method\nsynchronized void increment() { count++; }\n// Synchronized block\nvoid increment() {\n    synchronized(this) { count++; }\n}\n// Static synchronized (class-level lock)\nstatic synchronized void decrement() { count--; }`, codeLanguage:"java", explanation:"Instance method: locks on this object. Static method: locks on Class object. Block: locks on specified object. Only one thread can hold a lock at a time. Other threads block waiting. Avoid over-synchronization—causes contention." },
      { id:"mt4", question:"What is the difference between wait() and sleep()?", answer:"wait(): releases lock, must be called in synchronized block, notified by notify(). sleep(): keeps lock, doesn't need synchronized, wakes after time.", code:`// wait() — releases lock\nsynchronized(lock) {\n    while(!condition) lock.wait(); // releases lock\n    // do work\n}\n// sleep() — keeps lock\nThread.sleep(1000); // doesn't release lock`, codeLanguage:"java", explanation:"wait: Object method, releases lock, needs notify/notifyAll to wake, must be in synchronized. sleep: Thread method, keeps lock, auto-wakes after time, anywhere. wait is for inter-thread communication; sleep is for pause." },
      { id:"mt5", question:"notify() vs notifyAll()?", answer:"notify(): wakes ONE waiting thread (arbitrary). notifyAll(): wakes ALL waiting threads. Both must be called in synchronized context.", code:`synchronized(lock) {\n    condition=true;\n    lock.notify();    // one random thread\n    lock.notifyAll(); // all waiting threads\n}`, codeLanguage:"java", explanation:"notify: one thread woken, others still wait. Risk: wrong thread wakes, others starve. notifyAll: all woken, they compete for lock. Safer, use when multiple threads wait. Both must be in synchronized on same object." },
      { id:"mt6", question:"What is a deadlock? How to prevent it?", answer:"Deadlock: two+ threads each wait for a lock held by the other. Prevent by: consistent lock ordering, timeout, avoiding nested locks.", code:`// Deadlock scenario\nThread1: lock A → lock B\nThread2: lock B → lock A\n// Both wait forever!\n\n// Prevention: always lock in same order\n// Both threads: lock A → lock B (consistent order)`, codeLanguage:"java", explanation:"Causes: circular wait, inconsistent lock ordering. Prevent: 1) Lock in consistent order, 2) Use tryLock() with timeout, 3) Avoid nested locks, 4) Use higher-level concurrency utilities (java.util.concurrent)." },
      { id:"mt7", question:"What is the volatile keyword?", answer:"volatile ensures variable reads/writes go directly to main memory (not cached). Guarantees visibility across threads but NOT atomicity.", code:`class Shared {\n    volatile boolean running=true;\n    void stop() { running=false; } // visible to all threads\n}\n// Without volatile, thread may cache running=true forever`, codeLanguage:"java", explanation:"volatile: visibility guarantee (one thread writes, all see it). No atomicity (count++ still unsafe—use AtomicInteger). Prevents instruction reordering. Use for flags, one-way state. For atomic ops, use AtomicInteger/Long." },
      { id:"mt8", question:"What is the ExecutorService framework?", answer:"ExecutorService manages thread pools. Submit tasks, get Futures, manage lifecycle. Replaces manual thread creation.", code:`ExecutorService es=Executors.newFixedThreadPool(4);\nFuture<String> f=es.submit(() -> "result");\nSystem.out.println(f.get());\nes.shutdown();\n// Types: newFixedThreadPool, newCachedThreadPool,\n// newSingleThreadExecutor, newScheduledThreadPool`, codeLanguage:"java", explanation:"Fixed: constant pool size. Cached: creates as needed, reuses idle. Single: one thread, sequential. Scheduled: delayed/periodic tasks. Always shutdown() when done. submit() returns Future; execute() doesn't." },
      { id:"mt9", question:"What is the difference between Callable and Runnable?", answer:"Runnable: no return value, no checked exception. Callable: returns value via Future, can throw checked exception.", code:`// Runnable — void return\nRunnable r=() -> System.out.println("run");\n// Callable — returns value\nCallable<Integer> c=() -> 42;\nFuture<Integer> f=es.submit(c);\nint result=f.get(); // 42`, codeLanguage:"java", explanation:"Runnable: void run(), no checked exceptions. Callable: V call(), returns V, can throw Exception. Callable used with Future for async results. Both functional interfaces since Java 8." },
      { id:"mt10", question:"What is CountDownLatch?", answer:"Synchronization aid: one or more threads wait until a set of operations completes. Count is decremented; threads proceed when count reaches 0.", code:`CountDownLatch latch=new CountDownLatch(3);\n// Worker threads\nnew Thread(() -> { work(); latch.countDown(); }).start();\nnew Thread(() -> { work(); latch.countDown(); }).start();\nnew Thread(() -> { work(); latch.countDown(); }).start();\nlatch.await(); // blocks until count=0\nSystem.out.println("All done!");`, codeLanguage:"java", explanation:"countDown(): decrements counter. await(): blocks until counter=0. One-time use (cannot reset). Use for: waiting for N services to start, parallel task completion. For reusable barrier, use CyclicBarrier." },
    ],
  },
  {
    id: "inner-classes",
    title: "Inner Classes & Lambda",
    icon: "🎯",
    questions: [
      { id:"ic1", question:"What are the types of inner classes in Java?", answer:"4 types: Member inner class, Static nested class, Local inner class, Anonymous inner class.", code:`class Outer {\n    class Inner { }                    // member\n    static class Nested { }           // static nested\n    void method() {\n        class Local { }               // local\n        Runnable r=new Runnable() {   // anonymous\n            public void run() { }\n        };\n    }\n}`, codeLanguage:"java", explanation:"Member: has access to outer instance. Static nested: no outer instance needed. Local: inside method, limited scope. Anonymous: no name, one-time use. Java 8+: lambdas replace many anonymous inner classes." },
      { id:"ic2", question:"What is a functional interface?", answer:"Interface with exactly one abstract method. Annotated with @FunctionalInterface. Can have default and static methods.", code:`@FunctionalInterface\ninterface Printable {\n    void print(String s);\n    // default and static methods OK\n    default void log() { }\n    static void info() { }\n}\nPrintable p=s -> System.out.println(s);`, codeLanguage:"java", explanation:"One abstract method required. @FunctionalInterface is optional but recommended (compiler check). Examples: Runnable, Callable, Comparator, Predicate, Function, Consumer, Supplier." },
      { id:"ic3", question:"What is a lambda expression?", answer:"Concise way to represent a functional interface implementation. Introduced in Java 8.", code:`// Anonymous class\nRunnable r1=new Runnable() {\n    public void run() { System.out.println("Hi"); }\n};\n// Lambda\nRunnable r2=() -> System.out.println("Hi");\n// With parameters\nComparator<String> c=(a,b) -> a.length()-b.length();\n// With body\nComparator<String> c2=(a,b) -> {\n    int diff=a.length()-b.length();\n    return diff;\n};`, codeLanguage:"java", explanation:"Syntax: (params) -> expression or (params) -> { body }. Type inference on params. Single param: no parens needed (x -> x*2). Must target a functional interface. Replaces verbose anonymous inner classes." },
      { id:"ic4", question:"What are method references?", answer:"Shorthand for lambdas that call a single existing method. Four types: static, instance, particular type, constructor.", code:`// Static method reference\nFunction<String,Integer> f=Integer::parseInt;\n// Instance method reference (specific object)\nString s="hello";\nSupplier<String> sup=s::toUpperCase;\n// Instance method reference (type parameter)\nFunction<String,Integer> len=String::length;\n// Constructor reference\nSupplier<List<String>> list=ArrayList::new;`, codeLanguage:"java", explanation:"Static: ClassName::staticMethod. Instance: object::method. Type: ClassName::instanceMethod. Constructor: ClassName::new. Equivalent to lambda but more readable when just calling one method." },
      { id:"ic5", question:"What are the core functional interfaces in java.util.function?", answer:"Predicate, Function, Consumer, Supplier, and their variants (BiPredicate, BiFunction, UnaryOperator, etc.).", code:`Predicate<String> isEmpty=s -> s.isEmpty();\nFunction<String,Integer> len=s -> s.length();\nConsumer<String> print=s -> System.out.println(s);\nSupplier<Double> random=() -> Math.random();\nBiFunction<String,String,Integer> cmp=(a,b) -> a.compareTo(b);`, codeLanguage:"java", explanation:"Predicate<T>: T→boolean. Function<T,R>: T→R. Consumer<T>: T→void. Supplier<T>: ()->T. Bi- variants take 2 args. UnaryOperator<T>: T→T. Primitive variants: IntPredicate, IntFunction, etc." },
    ],
  },
  {
    id: "generics",
    title: "Generics",
    icon: "🔲",
    questions: [
      { id:"g1", question:"What are generics in Java?", answer:"Generics allow classes/interfaces/methods to operate on specified types. Provide compile-time type safety and eliminate casting.", code:`// Without generics\nList list=new ArrayList();\nlist.add("hello");\nString s=(String)list.get(0); // cast needed\n\n// With generics\nList<String> list2=new ArrayList<>();\nlist2.add("hello");\nString s2=list2.get(0); // no cast`, codeLanguage:"java", explanation:"Type safety at compile time. Eliminates runtime ClassCastException. No manual casting. Also used for: Map<K,V>, Comparable<T>, etc. Type erasure: generics info removed at runtime." },
      { id:"g2", question:"What is type erasure?", answer:"Java removes generic type info at compile time. At runtime, List<String> and List<Integer> are both just List.", code:`// Source code\nList<String> strings=new ArrayList<>();\nList<Integer> ints=new ArrayList<>();\n// After erasure: both are just List\n// strings.getClass()==ints.getClass() → true\n\n// Bridge methods generated by compiler for polymorphism`, codeLanguage:"java", explanation:"Compiler erases type params→Object (or bound). Inserts casts at call sites. Generates bridge methods for polymorphism. Cannot do: new T(), instanceof T, T.class, static T field. Runtime: no generic type info (reifiable types exception)." },
      { id:"g3", question:"What are bounded type parameters?", answer:"Restrict type parameter to a specific type or subtype. <T extends X> means T must be X or subclass.", code:`// Upper bound\n<T extends Number> void sum(List<T> list)\n// Multiple bounds\n<T extends Number & Comparable<T>> void sort(List<T> list)\n// Lower bound (wildcard only)\nvoid addAll(List<? super Integer> list)`, codeLanguage:"java", explanation:"Upper bound: T extends Class/Interface. Multiple: T extends Class & Interface1 & Interface2. Class must be first. Lower bound: ? super X (wildcard only). Bounded types allow calling methods of the bound." },
      { id:"g4", question:"What is the difference between <? extends T> and <? super T>?", answer:"PECS: Producer Extends, Consumer Super. extends=read-only (producer). super=write-only (consumer).", code:`// Producer (read from) → extends\nvoid printAll(List<? extends Number> list) {\n    for(Number n:list) System.out.println(n); // read OK\n    // list.add(1); // COMPILE ERROR — can't write\n}\n// Consumer (write to) → super\nvoid addInts(List<? super Integer> list) {\n    list.add(1); list.add(2); // write OK\n    // Integer i=list.get(0); // COMPILE ERROR — can't read\n}`, codeLanguage:"java", explanation:"PECS rule: If you READ from collection→? extends T. If you WRITE to collection→? super T. If both→? T (or don't use wildcard). ? extends T=upper bounded wildcard. ? super T=lower bounded wildcard." },
      { id:"g5", question:"Can you create a generic array?", answer:"No. Generic array creation is not allowed due to type erasure. Workaround: use List<T> or cast via Array.newInstance.", code:`// NOT allowed\nT[] array=new T[10]; // compile error\nList<String>[] arr=new List<String>[1]; // error\n\n// Workarounds\nList<T> list=new ArrayList<>(); // use List\n@SuppressWarnings("unchecked")\nT[] arr=(T[])new Object[10]; // unchecked cast\nT[] arr2=(T[])Array.newInstance(clazz,10); // reflection`, codeLanguage:"java", explanation:"Type erasure makes T[] unsafe at runtime (would be Object[] but compiler can't guarantee type safety). Use List<T> instead. If array needed, use reflection with Array.newInstance(clazz, size)." },
    ],
  },
  {
    id: "io",
    title: "I/O & Serialization",
    icon: "📁",
    questions: [
      { id:"io1", question:"What is the difference between InputStream/OutputStream and Reader/Writer?", answer:"InputStream/OutputStream: byte-based (binary). Reader/Writer: character-based (text). Reader/Writer handle character encoding.", code:`// Byte streams\nFileInputStream fis=new FileInputStream("data.bin");\nFileOutputStream fos=new FileOutputStream("out.bin");\n// Character streams\nFileReader fr=new FileReader("text.txt");\nFileWriter fw=new FileWriter("out.txt");`, codeLanguage:"java", explanation:"Byte streams: for binary data (images, audio). Character streams: for text, handle encoding automatically. InputStreamReader bridges byte→char. Always close streams (try-with-resources)." },
      { id:"io2", question:"What is BufferedReader? Why use it?", answer:"BufferedReader reads text with buffering for efficiency. Reduces I/O operations by reading chunks into buffer.", code:`BufferedReader br=new BufferedReader(new FileReader("file.txt"));\nString line;\nwhile((line=br.readLine())!=null) {\n    System.out.println(line);\n}\nbr.close();`, codeLanguage:"java", explanation:"Without buffer: each read() = system call (slow). With buffer: reads chunk into memory, serves from buffer (fast). BufferedReader: readLine() convenience. BufferedWriter: newLine(). Always chain: BufferedReader(new FileReader())." },
      { id:"io3", question:"What is serialization? How to implement it?", answer:"Converting object to byte stream for storage/transmission. Implement Serializable interface. ObjectInputStream/ObjectOutputStream for read/write.", code:`class Employee implements Serializable {\n    private static final long serialVersionUID=1L;\n    String name; int id;\n    transient String password; // not serialized\n}\n// Write\nObjectOutputStream oos=new ObjectOutputStream(\n    new FileOutputStream("emp.dat"));\noos.writeObject(new Employee("Alice",1,"secret"));\n// Read\nObjectInputStream ois=new ObjectInputStream(\n    new FileInputStream("emp.dat"));\nEmployee e=(Employee)ois.readObject();`, codeLanguage:"java", explanation:"Serializable: marker interface (no methods). serialVersionUID: version control, prevents InvalidClassException. transient: skip field. Externalizable: custom serialization (readExternal/writeExternal). Not serialized: static fields." },
      { id:"io4", question:"What is the transient keyword?", answer:"transient prevents a field from being serialized. Used for sensitive data or non-serializable objects.", code:`class User implements Serializable {\n    String name;\n    transient String password;  // NOT serialized\n    transient Logger log;      // NOT serialized (not Serializable)\n}`, codeLanguage:"java", explanation:"transient fields get default values after deserialization (null, 0, false). Use for: passwords, connections, threads, non-serializable objects. Static fields are also not serialized (regardless of transient)." },
      { id:"io5", question:"What is the difference between Serializable and Externalizable?", answer:"Serializable: automatic, uses reflection, slower. Externalizable: manual, developer controls what to serialize, faster.", code:`class Emp implements Externalizable {\n    String name; int id;\n    public void writeExternal(ObjectOutput out) throws IOException {\n        out.writeUTF(name); out.writeInt(id); // custom write\n    }\n    public void readExternal(ObjectInput in) throws IOException {\n        name=in.readUTF(); id=in.readInt(); // custom read\n    }\n}`, codeLanguage:"java", explanation:"Serializable: zero-config, reflection-based, all non-transient fields. Externalizable: must implement readExternal/writeExternal, no-arg constructor required, selective serialization, better performance." },
    ],
  },
  {
    id: "memory",
    title: "Memory & JVM",
    icon: "🧠",
    questions: [
      { id:"mem1", question:"How is memory divided in JVM?", answer:"JVM memory: Heap (objects), Stack (method frames), Method Area (class metadata), PC Register, Native Method Stack.", code:`// JVM Memory Layout:\n// ┌─────────────────────────────────┐\n// │           HEAP                   │\n// │  Young Gen: Eden + S0 + S1      │\n// │  Old Gen (Tenured)              │\n// │  MetaSpace (Java 8+)            │\n// ├─────────────────────────────────┤\n// │           STACK (per thread)     │\n// │  Local vars, operands, frames   │\n// ├─────────────────────────────────┤\n// │     Method Area / MetaSpace      │\n// │  Class info, constants, statics  │\n// └─────────────────────────────────┘`, codeLanguage:"plaintext", explanation:"Heap: all objects, shared across threads. GC manages heap. Stack: per-thread, method frames, local variables. Method Area: class metadata, static vars, constants (MetaSpace in Java 8+). PC Register: current instruction address. Native Stack: for native methods." },
      { id:"mem2", question:"What is garbage collection in Java?", answer:"Automatic memory management. GC identifies and deletes unreachable objects. JVM triggers GC when heap is low.", code:`Object obj=new Object();\nobj=null; // eligible for GC\nobj=new Object(); // previous object eligible\n// System.gc(); // suggests GC (not guaranteed)\n\n// Object with no references → eligible for GC\n// Island of isolation: circular refs with no external ref`, codeLanguage:"java", explanation:"GC algorithms: Mark-and-Sweep, Copying, Generational. HotSpot JVM: Generational GC (Young+Old). Young: Eden→Survivor→Old. GC types: Minor (Young), Major (Old), Full (entire heap). System.gc() is a hint, not a command." },
      { id:"mem3", question:"What is the difference between heap and stack memory?", answer:"Heap: shared, stores objects, managed by GC. Stack: per-thread, stores primitives and references, auto-managed with method calls.", code:`void method() {\n    int x=10;            // stack (primitive)\n    Object obj=new Object(); // obj ref on stack, object on heap\n    String s="hello";    // ref on stack, string in pool/heap\n} // x, obj, s popped from stack; heap objects eligible for GC`, codeLanguage:"java", explanation:"Heap: shared, objects, GC managed, larger, slower access, OutOfMemoryError. Stack: per-thread, primitives+refs, LIFO auto-managed, smaller, faster, StackOverflowError. Stack overflow: deep recursion. Heap overflow: too many objects." },
      { id:"mem4", question:"What makes an object eligible for garbage collection?", answer:"Object is eligible when no live thread can reach it. Nullifying references, reassigning references, or island of isolation.", code:`Object a=new Object();\nObject b=new Object();\na=b; // first object eligible\na=null; b=null; // both eligible\n\n// Island of isolation\nclass Node { Node next; }\nNode n1=new Node(); Node n2=new Node();\nn1.next=n2; n2.next=n1;\nn1=null; n2=null; // both eligible (island)`, codeLanguage:"java", explanation:"Eligibility: no reference from any live thread, null reference, reassigning reference, island of isolation (circular refs with no external ref). finalize() called once before GC (deprecated). Object.clone() and GC: no direct relation." },
      { id:"mem5", question:"What are the different garbage collectors in JVM?", answer:"Serial (single-thread), Parallel (throughput), CMS (low pause, deprecated), G1 (balanced, default Java 9+), ZGC (low latency), Shenandoah (low pause).", code:`// JVM flags:\n-XX:+UseSerialGC      // single-thread, small apps\n-XX:+UseParallelGC    // throughput-focused\n-XX:+UseG1GC          // balanced (default Java 9+)\n-XX:+UseZGC           // low latency (Java 11+)\n-XX:+UseShenandoahGC  // low pause (Java 12+)`, codeLanguage:"shell", explanation:"Serial: simple, stop-the-world. Parallel: multiple GC threads, best throughput. G1: region-based, balanced pause/throughput, default. ZGC: concurrent, <1ms pause. Shenandoah: concurrent compaction. Choose based on: heap size, pause requirements, throughput needs." },
    ],
  },
  {
    id: "streams-api",
    title: "Java 8 Stream API",
    icon: "🌊",
    questions: [
      { id:"st1", question:"What is the Stream API?", answer:"Stream API (Java 8) provides functional-style operations on collections. Supports sequential and parallel processing with lazy evaluation.", code:`List<String> names=List.of("Alice","Bob","Charlie","Anna");\nList<String> result=names.stream()\n    .filter(n -> n.startsWith("A"))\n    .map(String::toUpperCase)\n    .sorted()\n    .collect(Collectors.toList());\n// [ALICE, ANNA]`, codeLanguage:"java", explanation:"Stream: pipeline of operations. Lazy: intermediate ops execute only when terminal op called. Operations: intermediate (filter, map, sorted, distinct, limit) + terminal (collect, forEach, reduce, count, findFirst). Can be parallel with .parallelStream()." },
      { id:"st2", question:"What is the difference between map() and flatMap()?", answer:"map(): transforms each element 1:1 (Stream<R>). flatMap(): transforms each element 1:N and flattens (Stream<R> from Stream<Stream<R>>).", code:`// map: 1-to-1\nList<String> upper=names.stream()\n    .map(String::toUpperCase)\n    .collect(Collectors.toList());\n\n// flatMap: 1-to-N + flatten\nList<List<String>> nested=List.of(\n    List.of("a","b"), List.of("c","d"));\nList<String> flat=nested.stream()\n    .flatMap(Collection::stream)\n    .collect(Collectors.toList()); // [a,b,c,d]`, codeLanguage:"java", explanation:"map: each element→one element. Function<T,R>. flatMap: each element→stream of elements, all flattened. Function<T,Stream<R>>. Use map for simple transform, flatMap when each element maps to multiple values (nested collections, splitting strings)." },
      { id:"st3", question:"What is the difference between findFirst() and findAny()?", answer:"findFirst(): returns first element in encounter order (deterministic). findAny(): returns any element (non-deterministic, faster in parallel).", code:`List<String> list=List.of("A","B","C","D");\nlist.stream().findFirst(); // Optional[A] — always first\nlist.stream().findAny();   // Optional[A] — any element\nlist.parallelStream().findAny(); // may vary`, codeLanguage:"java", explanation:"findFirst: deterministic, respects encounter order, slightly slower in parallel. findAny: no order constraint, faster in parallel streams. Both return Optional. Use findFirst when order matters, findAny when any match suffices." },
      { id:"st4", question:"What are the different Collectors?", answer:"Collectors provide reduction operations: toList, toSet, toMap, joining, groupingBy, partitioningBy, counting, summarizing.", code:`// toList, toSet, toMap\nList<String> list=stream.collect(Collectors.toList());\nSet<String> set=stream.collect(Collectors.toSet());\nMap<String,Integer> map=stream.collect(Collectors.toMap(s->s, String::length));\n\n// joining\nString joined=stream.collect(Collectors.joining(", "));\n\n// groupingBy\nMap<Integer,List<String>> byLen=stream.collect(\n    Collectors.groupingBy(String::length));\n\n// partitioningBy (2 groups)\nMap<Boolean,List<String>> byLen5=stream.collect(\n    Collectors.partitioningBy(s -> s.length()>5));\n\n// counting, summingInt, averagingInt\nlong count=stream.collect(Collectors.counting());`, codeLanguage:"java", explanation:"toList/toSet/toMap: basic collection creation. joining: concatenate strings. groupingBy: SQL GROUP BY equivalent. partitioningBy: boolean key grouping. counting/summing/averaging: statistics. collectingAndThen: post-process. teeing (Java 12): two collectors." },
      { id:"st5", question:"What is the difference between intermediate and terminal operations?", answer:"Intermediate: lazy, return Stream, can be chained (filter, map, sorted). Terminal: eager, produce result, end pipeline (collect, forEach, reduce).", code:`// Intermediate (lazy — nothing happens until terminal)\nStream<String> s=list.stream()\n    .filter(n -> n.length()>3)  // intermediate\n    .map(String::toUpperCase);   // intermediate\n// Nothing executed yet!\n\n// Terminal (triggers execution)\nList<String> result=s.collect(Collectors.toList()); // now executes`, codeLanguage:"java", explanation:"Intermediate: lazy, short-circuiting possible (limit, takeWhile). Terminal: eager, produces result or side-effect. Only one terminal per stream. Stream is consumed after terminal operation. Short-circuit terminals: findFirst, findAny, anyMatch, allMatch, noneMatch." },
    ],
  },
  {
    id: "misc",
    title: "Miscellaneous & Advanced",
    icon: "🎓",
    questions: [
      { id:"m1", question:"What is the difference between shallow copy and deep copy?", answer:"Shallow copy: copies object, references point to same objects. Deep copy: copies object AND recursively copies all referenced objects.", code:`// Shallow copy (clone)\nclass Address { String city; }\nclass Person implements Cloneable {\n    String name; Address addr;\n    protected Object clone() throws CloneNotSupportedException {\n        return super.clone(); // shallow — addr shared\n    }\n}\n// Deep copy\nprotected Object clone() throws CloneNotSupportedException {\n    Person p=(Person)super.clone();\n    p.addr=new Address(); // new Address object\n    p.addr.city=this.addr.city; // copy values\n    return p;\n}`, codeLanguage:"java", explanation:"Shallow: clone() default behavior, nested objects shared. Deep: must manually clone nested objects. Deep copy alternatives: copy constructor, serialization, deep cloning libraries. Changes to shared objects affect both copies in shallow." },
      { id:"m2", question:"What is the Cloneable interface?", answer:"Marker interface indicating clone() is supported. Without it, Object.clone() throws CloneNotSupportedException.", code:`class Student implements Cloneable {\n    String name;\n    protected Object clone() throws CloneNotSupportedException {\n        return super.clone(); // shallow copy\n    }\n}\nStudent s1=new Student();\nStudent s2=(Student)s1.clone();`, codeLanguage:"java", explanation:"Cloneable: marker interface (no methods). Object.clone(): protected, shallow copy by default. Must override clone() as public for external use. Cloneable is considered broken by many—prefer copy constructor or factory method." },
      { id:"m3", question:"What is the difference between Comparator nullsFirst and nullsLast?", answer:"nullsFirst: nulls come before non-null. nullsLast: nulls come after non-null. Used with Comparator for null-safe sorting.", code:`List<String> list=Arrays.asList("B",null,"A",null,"C");\nlist.sort(Comparator.nullsFirst(Comparator.naturalOrder()));\n// [null, null, A, B, C]\nlist.sort(Comparator.nullsLast(Comparator.naturalOrder()));\n// [A, B, C, null, null]`, codeLanguage:"java", explanation:"nullsFirst: nulls sorted first, then non-null by specified comparator. nullsLast: non-null sorted first, then nulls. Without these, sorting with nulls throws NPE. Useful for database-like sorting." },
      { id:"m4", question:"What is the Optional class?", answer:"Container object that may or may not contain a non-null value. Prevents NullPointerException. Java 8+.", code:`Optional<String> opt=Optional.ofNullable(getName());\n// Check\nif(opt.isPresent()) { }\nopt.ifPresent(s -> System.out.println(s));\n// Get with default\nString name=opt.orElse("Unknown");\nString name2=opt.orElseGet(() -> getDefault());\n// Throw if empty\nString name3=opt.orElseThrow(() -> new RuntimeException());\n// Transform\nOptional<Integer> len=opt.map(String::length);`, codeLanguage:"java", explanation:"of(): non-null required (NPE if null). ofNullable(): null allowed. isPresent(): has value. ifPresent(): consume if present. orElse/orElseGet/orElseThrow: default values. map/flatMap/filter: transform. Never use Optional for fields or method parameters—only for return types." },
      { id:"m5", question:"What is the difference between varargs and array parameter?", answer:"varargs: flexible arg count (0 to many), syntax: Type... name. Array: fixed structure. Internally varargs is an array.", code:`// varargs — flexible number of arguments\nint sum(int... nums) {\n    int total=0;\n    for(int n:nums) total+=n;\n    return total;\n}\nsum();        // 0\nsum(1,2,3);   // 6\nsum(new int[]{1,2,3}); // also works\n\n// Must be last parameter\nvoid print(String format, Object... args) { }`, codeLanguage:"java", explanation:"varargs: Type... name, must be last parameter, only one per method, compiler creates array. Overloading with varargs can be ambiguous. Prefer explicit array when arg count is known/fixed. Varargs creates array each call (minor overhead)." },
      { id:"m6", question:"What is the difference between class loader types?", answer:"Bootstrap (loads JDK core classes), Extension/Platform (loads JDK extensions), Application/System (loads app classes from classpath).", code:`// Class loader hierarchy (parent delegation):\n// Bootstrap (rt.jar, java.lang.*)\n//   ↑ Platform (jdk/ext dirs, Java 9+ modules)\n//     ↑ Application (classpath, your classes)\n\n// Check class loader\nString.class.getClassLoader(); // null (bootstrap)\nMyClass.class.getClassLoader(); // AppClassLoader`, codeLanguage:"java", explanation:"Parent Delegation: child asks parent first, prevents overriding core classes. Bootstrap: C++ implemented, loads JDK internals. Platform: JDK extensions. Application: user classpath. Custom: can be created for plugins, hot-deploy." },
      { id:"m7", question:"What is the difference between shallow comparison and deep comparison?", answer:"Shallow: == compares references. Deep: .equals() compares content. For arrays: Arrays.equals() for deep, == for shallow.", code:`String[] a1={"A","B"}; String[] a2={"A","B"};\na1==a2;                  // false (different arrays)\na1.equals(a2);          // false (array equals=ref)\nArrays.equals(a1,a2);   // true (element-by-element)\n\nint[][] d1={{1,2},{3}}; int[][] d2={{1,2},{3}};\nArrays.equals(d1,d2);   // false (nested arrays)\nArrays.deepEquals(d1,d2); // true (deep comparison)`, codeLanguage:"java", explanation:"==: reference comparison. .equals(): content for String/wrappers, reference for arrays. Arrays.equals(): element-by-element for 1D. Arrays.deepEquals(): recursive for nested arrays. Always use appropriate comparison method." },
      { id:"m8", question:"What are Java records? (Java 14+)", answer:"Records are immutable data carriers. Auto-generate constructor, getters, equals, hashCode, toString.", code:`record Point(int x, int y) { }\nrecord Employee(String name, int id, double salary) {\n    // Compact constructor for validation\n    public Employee {\n        if(salary<0) throw new IllegalArgumentException();\n    }\n}\nPoint p=new Point(3,4);\np.x(); // 3 (not getX())\np.y(); // 4`, codeLanguage:"java", explanation:"Records: final, immutable, extends java.lang.Record. Auto-generated: constructor, accessor methods (x(), not getX()), equals, hashCode, toString. Can add: compact constructors, static methods/fields, instance methods. Cannot: extend other classes, declare instance fields. Perfect for DTOs, value objects." },
      { id:"m9", question:"What is the difference between StringBuilder and StringBuffer capacity?", answer:"Default capacity: 16 chars. When exceeded: new capacity = (old*2)+2. StringBuilder: not thread-safe. StringBuffer: thread-safe (synchronized).", code:`StringBuilder sb=new StringBuilder();     // capacity 16\nStringBuilder sb2=new StringBuilder(100); // capacity 100\nsb.append("A very long string...");\nsb.capacity(); // auto-expanded\nsb.ensureCapacity(500); // ensure minimum capacity\nsb.trimToSize(); // reduce to actual size`, codeLanguage:"java", explanation:"Initial capacity: 16 (default) or specified. Growth: (old*2)+2 automatically. ensureCapacity(): pre-allocate to avoid repeated expansion. trimToSize(): release unused memory. StringBuilder preferred for single-thread, StringBuffer for multi-thread." },
      { id:"m10", question:"What are sealed classes? (Java 17)", answer:"Sealed classes restrict which classes can extend them. Declared with 'permits' clause. Combines interface openness with enum control.", code:`sealed class Shape permits Circle, Rectangle {\n    abstract double area();\n}\nfinal class Circle extends Shape {\n    double r;\n    double area() { return Math.PI*r*r; }\n}\nnon-sealed class Rectangle extends Shape {\n    double w, h;\n    double area() { return w*h; }\n}\n// Only Circle and Rectangle can extend Shape`, codeLanguage:"java", explanation:"sealed: restricts subclasses. permits: lists allowed subclasses. Subclass must be: final, sealed, or non-sealed. Benefits: exhaustive pattern matching, controlled hierarchy. Works with interfaces too. Enables compiler to check completeness in switch expressions." },
      { id:"m11", question:"What is the difference between Stack and Queue?", answer:"Stack: LIFO (last-in-first-out). Queue: FIFO (first-in-first-out). Deque supports both.", code:`// Stack (LIFO)\nDeque<String> stack=new ArrayDeque<>();\nstack.push("A"); stack.push("B");\nstack.pop(); // "B" (last in)\n\n// Queue (FIFO)\nQueue<String> queue=new LinkedList<>();\nqueue.offer("A"); queue.offer("B");\nqueue.poll(); // "A" (first in)\n\n// PriorityQueue — ordered by priority\nPriorityQueue<Integer> pq=new PriorityQueue<>();\npq.offer(3); pq.offer(1); pq.offer(2);\npq.poll(); // 1 (smallest first)`, codeLanguage:"java", explanation:"Stack: push/pop/peek, LIFO. Queue: offer/poll/peek, FIFO. Deque: both ends. PriorityQueue: ordered by natural/comparator. Prefer ArrayDeque over Stack (Stack extends Vector=synchronized overhead). ArrayDeque also better than LinkedList for queue/deque." },
      { id:"m12", question:"What is the difference between Enumeration and Iterator?", answer:"Enumeration: legacy (Vector, Hashtable), read-only. Iterator: modern, supports remove(), fail-fast. ListIterator: bidirectional.", code:`// Enumeration (legacy)\nVector<String> v=new Vector<>();\nEnumeration<String> e=v.elements();\nwhile(e.hasMoreElements()) e.nextElement();\n\n// Iterator (modern)\nIterator<String> it=list.iterator();\nwhile(it.hasNext()) { it.next(); it.remove(); }`, codeLanguage:"java", explanation:"Enumeration: legacy, hasMoreElements/nextElement, no remove, not fail-fast. Iterator: modern, hasNext/next/remove, fail-fast. ListIterator: add/set/previous/indices. Always prefer Iterator/ListIterator." },
      { id:"m13", question:"What is the difference between HashMap and Hashtable?", answer:"HashMap: not thread-safe, allows 1 null key, faster. Hashtable: thread-safe (synchronized), no null keys/values, legacy.", code:`Map<String,Integer> hm=new HashMap<>(); // not thread-safe\nhm.put(null,1); // OK\nMap<String,Integer> ht=new Hashtable<>(); // thread-safe\nht.put(null,1); // NullPointerException!`, codeLanguage:"java", explanation:"HashMap: modern, not synchronized, allows null, fail-fast iterator. Hashtable: legacy (Java 1.0), all methods synchronized, no null, not recommended. For thread-safe map: use ConcurrentHashMap instead of Hashtable." },
      { id:"m14", question:"What is the difference between Vector and ArrayList?", answer:"Vector: synchronized (thread-safe), legacy, doubles capacity. ArrayList: not synchronized, faster, grows by 50%.", code:`List<String> al=new ArrayList<>(); // not synchronized, faster\nList<String> v=new Vector<>();     // synchronized, slower\n// Both: dynamic array, random access O(1)`, codeLanguage:"java", explanation:"Vector: Java 1.0, all methods synchronized, 2x growth. ArrayList: Java 1.2, not synchronized, 1.5x growth. For thread-safe list: Collections.synchronizedList() or CopyOnWriteArrayList. ArrayList preferred in most cases." },
      { id:"m15", question:"What are wrapper classes? Why needed?", answer:"Wrapper classes convert primitives to objects. Needed for: Collections (can't store primitives), generics, utility methods (Integer.parseInt).", code:`// Primitives → Wrappers\nint → Integer    char → Character\nbyte → Byte      long → Long\nshort → Short    float → Float\ndouble → Double  boolean → Boolean\n\n// Usage\nList<Integer> list=new ArrayList<>();\nlist.add(42); // autoboxing\nint val=Integer.parseInt("42");\nint max=Integer.MAX_VALUE;`, codeLanguage:"java", explanation:"8 wrappers in java.lang. All extend Number except Character and Boolean. Immutable. Integer caches -128 to 127. Provide utility methods: parseInt, valueOf, MAX_VALUE, MIN_VALUE. Required for Collections and generics." },
      { id:"m16", question:"What is the difference between aggregation and composition?", answer:"Aggregation: weak has-a, parts can exist independently. Composition: strong has-a, parts destroyed with whole.", code:`// Aggregation — weak ownership\nclass Department { List<Teacher> teachers; }\n// Teacher exists without Department\n\n// Composition — strong ownership\nclass House { List<Room> rooms; }\n// Room doesn't exist without House`, codeLanguage:"java", explanation:"Aggregation: 'has-a', independent lifecycle, represented by empty diamond in UML. Composition: 'part-of', dependent lifecycle, filled diamond in UML. In composition, destroying whole destroys parts. In aggregation, parts survive." },
      { id:"m17", question:"What is the instanceof operator?", answer:"instanceof checks if an object is an instance of a specific class/interface/subclass. Returns boolean.", code:`Animal a=new Dog();\na instanceof Dog;    // true\na instanceof Animal;  // true\na instanceof Object;  // true\na instanceof Cat;     // false\n\n// Java 16+ pattern matching\nif(a instanceof Dog d) {\n    d.bark(); // d already cast\n}`, codeLanguage:"java", explanation:"instanceof: tests type at runtime, includes subclasses. null instanceof X always false. Java 16+: pattern variable `if(obj instanceof Type var)` — combines check and cast. Don't overuse—polymorphism is often better." },
      { id:"m18", question:"What is the difference between object cloning and object copying?", answer:"Cloning: creates new object with same state (clone()). Copying: creating new object and manually setting fields (copy constructor).", code:`// Clone\nclass Student implements Cloneable {\n    String name;\n    protected Object clone() { return super.clone(); }\n}\nStudent s2=(Student)s1.clone();\n\n// Copy constructor (preferred)\nclass Student {\n    String name;\n    Student(Student other) { this.name=other.name; }\n}\nStudent s2=new Student(s1);`, codeLanguage:"java", explanation:"Clone: Cloneable interface, clone() method, shallow by default. Copy constructor: simpler, type-safe, no Cloneable needed, handles deep copy easily. Most developers prefer copy constructor over clone. Joshua Bloch: 'clone is broken'." },
      { id:"m19", question:"What is the difference between String join() and StringJoiner?", answer:"String.join(): static method for simple joining. StringJoiner: class for customizable joining with prefix, suffix, and delimiter.", code:`// String.join — simple\nString s=String.join(",", "A","B","C"); // "A,B,C"\n\n// StringJoiner — customizable\nStringJoiner sj=new StringJoiner(", ", "[", "]");\nsj.add("A").add("B").add("C");\nString result=sj.toString(); // "[A, B, C]"`, codeLanguage:"java", explanation:"String.join: quick one-liner, varargs or Iterable. StringJoiner: builder pattern, prefix/suffix, add incrementally. StringJoiner used internally by Collectors.joining(). Use join for simple cases, StringJoiner for prefix/suffix." },
      { id:"m20", question:"What is the Java Module System? (Java 9)", answer:"Java Platform Module System (JPMS) organizes code into modules with explicit dependencies and encapsulation. module-info.java defines module.", code:`// module-info.java\nmodule com.myapp {\n    requires java.sql;           // dependency\n    requires transitive java.base; // transitive\n    exports com.myapp.api;       // public API\n    // com.myapp.internal not exported (encapsulated)\n}\n\n// Benefits:\n// - Strong encapsulation (no reflection into non-exported)\n// - Reliable dependency management\n// - Smaller deployment with jlink`, codeLanguage:"java", explanation:"module: group of packages. requires: dependencies. exports: public packages. opens: reflection access. transitive: dependency propagation. Benefits: strong encapsulation, reliable config, custom runtime (jlink). Challenges: migration effort, split packages, reflection restrictions." },
    ],
  },
];
